using namespace std;

int main() {
    string filename;
    string wordToFind;

    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to search for: ";
    cin >> wordToFind;

    ifstream inputFile(filename);

    if (!inputFile.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return 1;
    }

    int totalFrequency = 0;
    string line;

    while (getline(inputFile, line)) {
        stringstream ss(line);
        string word;
        while (ss >> word) {
            if (word == wordToFind) {
                totalFrequency++;
            }
        }
    }

    inputFile.close();

    cout << "Total frequency of '" << wordToFind << "' in " << filename << ": " << totalFrequency << endl;

    return 0;
}
